xpath.script:
//
(function () {
    "use strict";
    function updatePickupBanner() {
        var selected = document.querySelector('input[name="delivery_type"]:checked');
        var banner = document.getElementById('pickup_info_banner');
        if (!banner) return;
        if (selected && selected.dataset && selected.dataset.isPickup === '1') {
            banner.classList.remove('d-none');
        } else {
            banner.classList.add('d-none');
        }
    }
    document.addEventListener('DOMContentLoaded', function () {
        var radios = document.querySelectorAll('input[name="delivery_type"]');
        radios.forEach(function (r) {
            r.addEventListener('change', updatePickupBanner);
        });
        updatePickupBanner();
    });
})();
//

//
(function () {
    "use strict";
    function updatePickupMode() {
        var pickupRadio = document.getElementById('pickup_mode_pickup');
        var form = document.querySelector('form.checkout_autoformat');
        var banner = document.getElementById('pickup_store_banner');
        var hiddenInput = document.getElementById('pickup_at_store_input');
        var selector = document.getElementById('pickup_mode_selector');
        if (!pickupRadio || !form || !banner || !hiddenInput || !selector) {
            return;
        }
        var isPickup = pickupRadio.checked;
        hiddenInput.value = isPickup ? '1' : '0';

        // Address-related field selectors to hide/show
        var addrSelectors = [
            '.div_street', '.div_street2', '.div_city', '.div_zip',
            '.div_country', '.div_state_id', '.div_vat',
            '.div_company_name', '#div_email'
        ];
        addrSelectors.forEach(function (sel) {
            var els = form.querySelectorAll(sel);
            els.forEach(function (el) {
                el.style.display = isPickup ? 'none' : '';
            });
        });

        // Also hide the "Kirim ke alamat yang sama" toggle in pickup mode
        var useSame = document.getElementById('shipping_use_same');
        if (useSame) {
            var useSameContainer = useSame.closest('.form-check');
            if (useSameContainer) {
                useSameContainer.style.display = isPickup ? 'none' : '';
            }
        }
        // Also hide the GPS detect button (it's in #koordinat_input group)
        // Already covered by .div_street2 selector

        // Show/hide store info banner
        if (isPickup) {
            banner.classList.remove('d-none');
            var addr = selector.dataset.storeAddress || '';
            var hrs = selector.dataset.storeHours || '';
            var addrEl = document.getElementById('pickup_store_address_text');
            var hrsEl = document.getElementById('pickup_business_hours_text');
            if (addrEl) {
                addrEl.innerHTML = addr
                    ? '<i class="fa fa-map-marker me-1"></i>' + addr
                    : '';
            }
            if (hrsEl) {
                hrsEl.innerHTML = hrs
                    ? '<i class="fa fa-clock-o me-1"></i>' + hrs
                    : '';
            }
        } else {
            banner.classList.add('d-none');
        }
    }

    function setupPickupMode() {
        var delivery = document.getElementById('pickup_mode_delivery');
        var pickup = document.getElementById('pickup_mode_pickup');
        if (delivery) {
            delivery.addEventListener('change', updatePickupMode);
        }
        if (pickup) {
            pickup.addEventListener('change', updatePickupMode);
        }
        updatePickupMode();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', setupPickupMode);
    } else {
        setupPickupMode();
    }
    // Re-run after a delay in case the customizer JS reorganizes the DOM
    setTimeout(setupPickupMode, 500);
})();
//
